    // ── Cours 10 : Lire une étiquette alimentaire ─────────────────────────────
    const fpt10Id = randomUUID();
    this.courses.set(fpt10Id, {
      id: fpt10Id,
      title: "Lire une étiquette alimentaire",
      description: "Apprends à lire et comprendre une étiquette alimentaire canadienne : valeur nutritive, ingrédients et allergènes",
      category: "francais_fpt",
      content: "<h2>Lire une étiquette alimentaire</h2><p>Au Canada, tous les aliments emballés doivent avoir une étiquette. Savoir la lire te permet de faire de meilleurs choix alimentaires et de repérer les allergènes dangereux.</p><div style='background:#fef9c3;border-left:4px solid #eab308;padding:12px;margin:15px 0;border-radius:4px'><strong>Les 4 sections obligatoires d'une étiquette :</strong><br>1. Le <strong>tableau de la valeur nutritive</strong> — calories et nutriments par portion<br>2. La <strong>liste des ingrédients</strong> — du plus présent au moins présent<br>3. Les <strong>allergènes prioritaires</strong> — en gras ou dans une mention « Contient »<br>4. La <strong>date de péremption</strong> — « Meilleur avant » ou « Best before »</div><h3>Étiquette réelle — Yogourt aux fraises Liberté</h3><div style='color-scheme:light;background:#e5e7eb;padding:16px;border-radius:8px;margin:10px 0'><div style='background:#ffffff;color:#000000;font-family:Arial,Helvetica,sans-serif;font-size:0.78em;max-width:680px;margin:0 auto;border:1px solid #9ca3af;padding:12px'><div style='display:flex;gap:16px;flex-wrap:wrap;margin-bottom:10px'><div style='flex:1;min-width:200px'><div style='font-size:1.5em;font-weight:900;letter-spacing:-0.5px;color:#1a1a1a'>Liberté</div><div style='font-size:1.1em;font-weight:bold'>Yogourt aux fraises</div><div style='font-size:0.85em;color:#555'>Mélange de cultures actives</div><br><div style='font-size:0.9em'><strong>650 g</strong></div><br><div style='font-size:0.85em;color:#555'>Conserver au réfrigérateur<br>Réfrigérer à 0–4 °C</div><br><div style='font-size:0.85em'><span style='color:#b91c1c;font-weight:bold'>Meilleur avant / Best before :</span><br><strong style='font-size:1.05em'>2025 JN 08</strong></div><br><div style='font-size:0.8em;color:#555'>Produit du Québec<br>Liberté Inc., Montréal QC<br>1 800 361-5388<br>libertenaturel.com</div></div><div style='width:220px;flex-shrink:0'><div style='border:3px solid #000;padding:4px 6px'><div style='border-bottom:8px solid #000;padding-bottom:4px;margin-bottom:3px'><span style='font-size:1.3em;font-weight:900;display:block;line-height:1.1'>Valeur nutritive</span><span style='font-size:0.95em;font-weight:700;display:block'>Nutrition Facts</span></div><div style='font-size:0.82em;margin-bottom:2px'>Pour 175 g (3/4 tasse)<br>Per 175 g (3/4 cup)</div><div style='border-top:4px solid #000;border-bottom:1px solid #000;display:flex;justify-content:space-between;align-items:baseline;padding:3px 0'><span style='font-size:1.5em;font-weight:900;line-height:1'>Calories</span><span style='font-size:2em;font-weight:900;line-height:1'>150</span></div><div style='text-align:right;font-size:0.75em;font-style:italic;border-bottom:4px solid #000;padding:1px 0'>% valeur quotidienne*<br>% Daily Value*</div><div style='display:flex;justify-content:space-between;padding:2px 0;border-bottom:1px solid #000'><span><strong>Lipides / Fat</strong> 3 g</span><span><strong>4 %</strong></span></div><div style='display:flex;justify-content:space-between;padding:2px 0 2px 12px;border-bottom:1px solid #ccc;font-size:0.93em'><span>Saturés / Saturated 2 g</span><span><strong>10 %</strong></span></div><div style='display:flex;justify-content:space-between;padding:2px 0 2px 12px;border-bottom:1px solid #000;font-size:0.93em'><span>+ Trans / + trans 0 g</span><span></span></div><div style='display:flex;justify-content:space-between;padding:2px 0;border-bottom:1px solid #000'><span><strong>Glucides / Carbohydrate</strong> 25 g</span><span><strong>9 %</strong></span></div><div style='display:flex;justify-content:space-between;padding:2px 0 2px 12px;border-bottom:1px solid #ccc;font-size:0.93em'><span>Fibres / Fibre 0 g</span><span><strong>0 %</strong></span></div><div style='display:flex;justify-content:space-between;padding:2px 0 2px 12px;border-bottom:1px solid #000;font-size:0.93em'><span>Sucres / Sugars 22 g</span><span><strong>24 %</strong></span></div><div style='display:flex;justify-content:space-between;padding:2px 0;border-bottom:4px solid #000'><span><strong>Protéines / Protein</strong> 6 g</span><span></span></div><div style='display:flex;justify-content:space-between;padding:2px 0;border-bottom:1px solid #000;font-size:0.93em'><span>Cholestérol / Cholesterol 10 mg</span><span><strong>3 %</strong></span></div><div style='display:flex;justify-content:space-between;padding:2px 0;border-bottom:1px solid #000;font-size:0.93em'><span>Sodium 75 mg</span><span><strong>3 %</strong></span></div><div style='display:flex;justify-content:space-between;padding:2px 0;border-bottom:1px solid #000;font-size:0.93em'><span>Potassium 260 mg</span><span><strong>6 %</strong></span></div><div style='display:flex;justify-content:space-between;padding:2px 0;border-bottom:1px solid #000;font-size:0.93em'><span>Calcium / Calcium 200 mg</span><span><strong>15 %</strong></span></div><div style='display:flex;justify-content:space-between;padding:2px 0;border-bottom:3px solid #000;font-size:0.93em'><span>Fer / Iron 0 mg</span><span><strong>0 %</strong></span></div><div style='font-size:0.75em;padding-top:3px;line-height:1.4'>* 5 % ou moins = peu · 15 % ou plus = beaucoup<br><em>5% or less is a little · 15% or more is a lot</em></div></div></div></div><div style='border-top:1px solid #9ca3af;padding-top:8px;font-size:0.8em'><strong>INGRÉDIENTS :</strong> Lait écrémé, fraises (14 %), sucre, amidon de maïs modifié, arômes naturels, pectine, <strong>LAIT</strong> en poudre, cultures actives (<em>L. bulgaricus, S. thermophilus, L. acidophilus, bifidus</em>).<br><br><strong style='color:#b91c1c'>CONTIENT : LAIT. / CONTAINS: MILK.</strong>&nbsp;&nbsp; Peut contenir / May contain : noix / tree nuts, arachides / peanuts.<br><br><div style='display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px'><span style='color:#555'>Fabriqué au Québec / Made in Quebec</span><span style='font-family:monospace;font-size:0.9em;letter-spacing:2px;border:1px solid #000;padding:2px 6px'>0 57700 31482 6</span></div></div></div></div><h3>Comment lire la liste des ingrédients</h3><div style='background:#dcfce7;padding:10px;margin:10px 0;border-radius:4px'>Les ingrédients sont listés <strong>du plus présent au moins présent</strong>.<br>Exemple : le premier ingrédient (lait écrémé) est celui dont il y a le plus dans le yogourt.<br>Les fraises (14 %) viennent en 2e position.<br><br><strong>Allergènes prioritaires en gras :</strong> LAIT, OEUFS, ARACHIDES, NOIX, SÉSAME, BLÉ, SOYA, MOUTARDE, SULFITES, MOLLUSQUES, POISSONS, CRUSTACÉS</div><h3>Comprendre le % valeur quotidienne</h3><div style='background:#dbeafe;padding:10px;margin:10px 0;border-radius:4px'>Le <strong>% valeur quotidienne (% VQ)</strong> indique quelle portion de tes besoins journaliers un aliment fournit.<br><strong>5 % ou moins = PEU</strong> (ex : sodium 3 % → faible en sodium)<br><strong>15 % ou plus = BEAUCOUP</strong> (ex : calcium 15 % → bonne source de calcium)<br><br>Dans ce yogourt : <strong>sucres à 24 %</strong> = beaucoup de sucre pour une portion de 175 g.</div>",
      order: 209,
    } as any);

