    const fpt28Id = randomUUID();
    this.courses.set(fpt28Id, {
      id: fpt28Id,
      title: "Lire un bulletin scolaire du CFP",
      description: "Comprends comment lire ton bulletin de notes d'un centre de formation professionnelle : compétences, codes de résultat, et comment demander une révision",
      category: "francais_fpt",
      content: "<h2>Lire un bulletin scolaire du CFP</h2><p>Dans un centre de formation professionnelle (CFP), les notes fonctionnent différemment de l'école secondaire. Les cours sont divisés en <strong>compétences</strong> à maîtriser. Chaque compétence est évaluée individuellement et reçoit un code de résultat.</p><div style='background:#fef9c3;border-left:4px solid #eab308;padding:12px;margin:15px 0;border-radius:4px'><strong>Codes de résultat au CFP :</strong><br><strong>MA</strong> — Maîtrisé : la compétence est acquise (résultat ≥ 60 %)<br><strong>EC</strong> — En cours d'acquisition : la compétence est partiellement acquise<br><strong>NM</strong> — Non maîtrisé : la compétence doit être reprise (résultat &lt; 60 %)<br><strong>EX</strong> — Exempté : la compétence est reconnue par des acquis antérieurs<br><br>Pour obtenir ton DEP, tu dois avoir toutes les compétences avec le code <strong>MA</strong>. Si tu as un <strong>NM</strong>, tu dois reprendre cette compétence avant d'obtenir ton diplôme.</div><h3>Bulletin de notes — CFP des métiers de l'alimentation</h3><div style='color-scheme:light;background:#e5e7eb;padding:14px;border-radius:8px;margin:10px 0'><div style='background:#ffffff;color:#111827;font-family:Arial,Helvetica,sans-serif;font-size:0.76em;max-width:700px;margin:0 auto;border:1px solid #9ca3af'><div style='background:#2d5a27;color:#ffffff;padding:8px 14px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:6px'><div><strong style='font-size:1.05em'>CFP des métiers de l'alimentation</strong><br><span style='font-size:0.85em;color:#bbf7d0'>Commission scolaire de Montréal (CSDM)</span></div><div style='text-align:right'><div style='background:#ffffff;color:#2d5a27;padding:2px 10px;font-weight:900;font-size:0.9em'>BULLETIN DE NOTES</div><div style='font-size:0.8em;margin-top:2px;color:#bbf7d0'>Session automne 2025</div></div></div><div style='padding:8px 14px;border-bottom:1px solid #d1d5db;background:#f0fdf4'><div style='display:flex;justify-content:space-between;flex-wrap:wrap;gap:8px;font-size:0.88em'><div><div style='font-size:0.8em;color:#6b7280'>Élève</div><strong>TREMBLAY, Léa</strong><br>No d'élève : CFP-2025-0291</div><div><div style='font-size:0.8em;color:#6b7280'>Programme</div><strong>DEP — Cuisine d'établissement</strong><br>Code : 5297</div><div style='text-align:right'><div style='font-size:0.8em;color:#6b7280'>Heures complétées</div><strong>312 / 1800 h</strong></div></div></div><div style='padding:8px 14px;border-bottom:2px solid #2d5a27'><div style='background:#2d5a27;color:#fff;font-weight:700;font-size:0.82em;padding:3px 6px;margin-bottom:8px'>COMPÉTENCES — BLOC A : FONDEMENTS DE LA CUISINE</div><table style='width:100%;border-collapse:collapse;font-size:0.88em'><tr style='background:#f0fdf4'><th style='text-align:left;padding:4px 6px;border-bottom:1px solid #d1d5db;color:#6b7280'>Code</th><th style='text-align:left;padding:4px 6px;border-bottom:1px solid #d1d5db;color:#6b7280'>Compétence</th><th style='text-align:right;padding:4px 6px;border-bottom:1px solid #d1d5db;color:#6b7280'>Résultat</th><th style='text-align:center;padding:4px 6px;border-bottom:1px solid #d1d5db;color:#6b7280'>Code</th></tr><tr><td style='padding:4px 6px;color:#6b7280'>A01</td><td style='padding:4px 6px'>Santé, hygiène et salubrité alimentaire</td><td style='padding:4px 6px;text-align:right'>88 %</td><td style='padding:4px 6px;text-align:center'><span style='background:#15803d;color:#fff;padding:2px 8px;border-radius:3px;font-weight:700'>MA</span></td></tr><tr style='background:#f9fafb'><td style='padding:4px 6px;color:#6b7280'>A02</td><td style='padding:4px 6px'>Prévention des accidents et des incendies</td><td style='padding:4px 6px;text-align:right'>92 %</td><td style='padding:4px 6px;text-align:center'><span style='background:#15803d;color:#fff;padding:2px 8px;border-radius:3px;font-weight:700'>MA</span></td></tr><tr><td style='padding:4px 6px;color:#6b7280'>A03</td><td style='padding:4px 6px'>Utilisation des équipements de cuisine</td><td style='padding:4px 6px;text-align:right'>74 %</td><td style='padding:4px 6px;text-align:center'><span style='background:#15803d;color:#fff;padding:2px 8px;border-radius:3px;font-weight:700'>MA</span></td></tr><tr style='background:#f9fafb'><td style='padding:4px 6px;color:#6b7280'>A04</td><td style='padding:4px 6px'>Communication en cuisine (terminologie)</td><td style='padding:4px 6px;text-align:right'>54 %</td><td style='padding:4px 6px;text-align:center'><span style='background:#dc2626;color:#fff;padding:2px 8px;border-radius:3px;font-weight:700'>NM</span></td></tr><tr><td style='padding:4px 6px;color:#6b7280'>A05</td><td style='padding:4px 6px'>Calcul des quantités et des coûts</td><td style='padding:4px 6px;text-align:right'>—</td><td style='padding:4px 6px;text-align:center'><span style='background:#6b7280;color:#fff;padding:2px 8px;border-radius:3px;font-weight:700'>EC</span></td></tr></table></div><div style='padding:8px 14px;border-bottom:2px solid #2d5a27;background:#f9fafb'><div style='background:#2d5a27;color:#fff;font-weight:700;font-size:0.82em;padding:3px 6px;margin-bottom:8px'>COMPÉTENCES — BLOC B : TECHNIQUES DE BASE</div><table style='width:100%;border-collapse:collapse;font-size:0.88em'><tr style='background:#f0fdf4'><th style='text-align:left;padding:4px 6px;border-bottom:1px solid #d1d5db;color:#6b7280'>Code</th><th style='text-align:left;padding:4px 6px;border-bottom:1px solid #d1d5db;color:#6b7280'>Compétence</th><th style='text-align:right;padding:4px 6px;border-bottom:1px solid #d1d5db;color:#6b7280'>Résultat</th><th style='text-align:center;padding:4px 6px;border-bottom:1px solid #d1d5db;color:#6b7280'>Code</th></tr><tr><td style='padding:4px 6px;color:#6b7280'>B01</td><td style='padding:4px 6px'>Taillage des légumes et des fruits</td><td style='padding:4px 6px;text-align:right'>81 %</td><td style='padding:4px 6px;text-align:center'><span style='background:#15803d;color:#fff;padding:2px 8px;border-radius:3px;font-weight:700'>MA</span></td></tr><tr style='background:#f9fafb'><td style='padding:4px 6px;color:#6b7280'>B02</td><td style='padding:4px 6px'>Préparation des fonds et des sauces</td><td style='padding:4px 6px;text-align:right'>—</td><td style='padding:4px 6px;text-align:center'><span style='background:#6b7280;color:#fff;padding:2px 8px;border-radius:3px;font-weight:700'>EC</span></td></tr></table></div><div style='padding:8px 14px'><div style='background:#2d5a27;color:#fff;font-weight:700;font-size:0.82em;padding:3px 6px;margin-bottom:6px'>RÉSUMÉ ET COMMENTAIRES</div><div style='display:grid;grid-template-columns:repeat(4,1fr);gap:6px;margin-bottom:8px;font-size:0.88em;text-align:center'><div style='background:#dcfce7;padding:6px;border-radius:4px'><div style='font-size:1.2em;font-weight:900;color:#15803d'>4</div><div style='color:#6b7280'>Maîtrisées (MA)</div></div><div style='background:#f9fafb;padding:6px;border-radius:4px'><div style='font-size:1.2em;font-weight:900;color:#6b7280'>2</div><div style='color:#6b7280'>En cours (EC)</div></div><div style='background:#fef2f2;padding:6px;border-radius:4px'><div style='font-size:1.2em;font-weight:900;color:#dc2626'>1</div><div style='color:#6b7280'>Non maîtrisée (NM)</div></div><div style='background:#f0fdf4;padding:6px;border-radius:4px'><div style='font-size:1.2em;font-weight:900;color:#2d5a27'>0</div><div style='color:#6b7280'>Exemptées (EX)</div></div></div><div style='background:#fef2f2;border-left:3px solid #dc2626;padding:6px 10px;font-size:0.88em;margin-bottom:6px'><strong>Attention :</strong> La compétence A04 (Communication en cuisine) doit être reprise. Léa doit s'inscrire à la reprise avant le 31 janvier 2026.</div><div style='font-size:0.85em;color:#374151'><strong>Commentaire de l'enseignante :</strong> Léa fait preuve d'un très bon sens pratique en cuisine. Son point à améliorer est le vocabulaire technique français. Je recommande de consulter le lexique fourni en classe et de pratiquer les termes à la maison.</div></div></div></div><h3>Demander une révision de note</h3><div style='background:#dcfce7;padding:10px;margin:10px 0;border-radius:4px'>Si tu penses qu'une note est incorrecte, tu as le droit de demander une <strong>révision</strong> dans les <strong>10 jours ouvrables</strong> suivant la réception du bulletin.<br><br><strong>Étapes :</strong><br>1. Parle d'abord à ton enseignant(e) pour comprendre la note<br>2. Si tu n'es pas satisfait(e), remplis le formulaire de demande de révision au secrétariat du CFP<br>3. Un comité de révision examine ta demande et te répond par écrit dans les 10 jours<br><br>La révision est gratuite et ne peut pas diminuer ta note si elle était correcte.</div>",
      order: 227,
    } as any);

