    // ── Cours 38 : Lire un bail résidentiel ──────────────────────────────────
    const fpt38Id = randomUUID();
    this.courses.set(fpt38Id, {
      id: fpt38Id,
      title: "Lire un bail résidentiel (contrat de location)",
      description: "Comprends les clauses essentielles d'un bail québécois : durée, loyer, dépôt, droit de visite, fin de bail — et connais tes droits comme locataire auprès du TAL",
      category: "francais_fpt",
      content: "<h2>Lire un bail résidentiel</h2><p>Au Québec, le <strong>bail résidentiel</strong> est un contrat obligatoire entre un locataire et un propriétaire. La loi québécoise protège les locataires : tu ne peux pas être expulsé sans raison valide, et ton propriétaire doit respecter des règles strictes. Le formulaire officiel est publié par le <strong>Tribunal administratif du logement (TAL)</strong>.</p><div style='background:#fef9c3;border-left:4px solid #eab308;padding:12px;margin:15px 0;border-radius:4px'><strong>Bon à savoir :</strong><br>· Au Québec, le propriétaire <strong>ne peut pas exiger de dépôt de garantie (dépôt de sécurité)</strong> — c'est illégal.<br>· Tu as le droit de <strong>sous-louer</strong> ton logement avec l'autorisation du propriétaire.<br>· Le propriétaire doit te donner un <strong>avis de 24 heures</strong> avant toute visite (sauf urgence).<br>· Ton loyer ne peut augmenter qu'<strong>une fois par an</strong>, avec un préavis de 3 mois.</div><h3>Extrait de bail — Léa Tremblay (Juin 2025)</h3><div style='color-scheme:light;background:#e5e7eb;padding:14px;border-radius:8px;margin:10px 0'><div style='background:#ffffff;color:#111827;font-family:Arial,Helvetica,sans-serif;font-size:0.76em;max-width:700px;margin:0 auto;border:1px solid #9ca3af'><div style='background:#003087;color:#ffffff;padding:7px 14px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:4px'><div><strong style='font-size:1.0em'>BAIL DE LOGEMENT</strong><br><span style='font-size:0.82em;color:#bfdbfe'>Formulaire officiel — Tribunal administratif du logement (TAL)</span></div><div style='text-align:right;font-size:0.82em;color:#bfdbfe'>No de dossier : BL-2025-48291<br>Province de Québec</div></div><div style='padding:10px 14px;border-bottom:1px solid #e5e7eb'><div style='font-weight:700;color:#003087;margin-bottom:6px;font-size:0.88em'>A — PARTIES AU BAIL</div><table style='width:100%;border-collapse:collapse;font-size:0.9em'><tr><td style='padding:3px 6px;width:120px;color:#6b7280'>Locataire :</td><td style='padding:3px 6px;font-weight:600'>Léa Tremblay</td><td style='padding:3px 6px;width:120px;color:#6b7280'>Tél. :</td><td style='padding:3px 6px'>514 555-0291</td></tr><tr><td style='padding:3px 6px;color:#6b7280'>Propriétaire :</td><td style='padding:3px 6px;font-weight:600'>Gestion Immobilière Beaumont Inc.</td><td style='padding:3px 6px;color:#6b7280'>Tél. :</td><td style='padding:3px 6px'>514 555-9400</td></tr></table></div><div style='padding:10px 14px;border-bottom:1px solid #e5e7eb'><div style='font-weight:700;color:#003087;margin-bottom:6px;font-size:0.88em'>B — LOGEMENT</div><table style='width:100%;border-collapse:collapse;font-size:0.9em'><tr><td style='padding:3px 6px;width:160px;color:#6b7280'>Adresse :</td><td style='padding:3px 6px;font-weight:600'>312, rue Lajeunesse, app. 4, Montréal (Qc) H2R 2H7</td></tr><tr><td style='padding:3px 6px;color:#6b7280'>Type de logement :</td><td style='padding:3px 6px'>4½ (1 chambre à coucher, salon, cuisine, salle de bain)</td></tr><tr><td style='padding:3px 6px;color:#6b7280'>Services inclus :</td><td style='padding:3px 6px'>Eau chaude · Stationnement extérieur no 12</td></tr><tr><td style='padding:3px 6px;color:#6b7280'>Services exclus :</td><td style='padding:3px 6px'>Électricité · Chauffage (Hydro-Québec au nom du locataire)</td></tr></table></div><div style='padding:10px 14px;border-bottom:1px solid #e5e7eb;background:#f0f9ff'><div style='font-weight:700;color:#003087;margin-bottom:6px;font-size:0.88em'>C — DURÉE ET LOYER</div><table style='width:100%;border-collapse:collapse;font-size:0.9em'><tr><td style='padding:3px 6px;width:200px;color:#6b7280'>Durée du bail :</td><td style='padding:3px 6px;font-weight:600'>12 mois — du 1er juillet 2025 au 30 juin 2026</td></tr><tr><td style='padding:3px 6px;color:#6b7280'>Loyer mensuel :</td><td style='padding:3px 6px;font-weight:700;color:#003087;font-size:1.05em'>850,00 $</td></tr><tr><td style='padding:3px 6px;color:#6b7280'>Date de paiement :</td><td style='padding:3px 6px'>Le 1er de chaque mois</td></tr><tr><td style='padding:3px 6px;color:#6b7280'>Mode de paiement :</td><td style='padding:3px 6px'>Chèque ou virement Interac</td></tr><tr><td style='padding:3px 6px;color:#6b7280'>Dépôt de garantie :</td><td style='padding:3px 6px;color:#dc2626;font-weight:600'>Interdit par la loi au Québec — aucun dépôt exigé</td></tr></table></div><div style='padding:10px 14px;border-bottom:1px solid #e5e7eb'><div style='font-weight:700;color:#003087;margin-bottom:6px;font-size:0.88em'>D — RÈGLEMENTS ET CONDITIONS</div><div style='font-size:0.9em;line-height:1.6'><strong>Animaux :</strong> Interdits dans le logement et les parties communes (clause 2.4).<br><strong>Sous-location :</strong> Permise avec autorisation écrite du propriétaire (article 1870 C.c.Q.).<br><strong>Droit de visite :</strong> Le propriétaire doit aviser le locataire <strong>24 heures à l'avance</strong> (sauf urgence).<br><strong>Entretien :</strong> Le locataire est responsable de l'entretien ménager courant. Le propriétaire est responsable des réparations majeures.<br><strong>Tabagisme :</strong> Interdit dans le logement et toutes les parties communes de l'immeuble.</div></div><div style='padding:10px 14px;border-bottom:1px solid #e5e7eb;background:#f0fdf4'><div style='font-weight:700;color:#003087;margin-bottom:6px;font-size:0.88em'>E — FIN DE BAIL ET RECONDUCTION</div><div style='font-size:0.9em;line-height:1.6'>Le locataire doit aviser le propriétaire par écrit s'il souhaite <strong>ne pas renouveler le bail</strong> :<br>· Pour un bail de 12 mois : entre <strong>3 et 6 mois avant la fin</strong> (donc entre le 1er janvier et le 31 mars 2026).<br>· Si aucun avis n'est donné, le bail se renouvelle automatiquement aux mêmes conditions.<br><br>Pour une <strong>augmentation de loyer</strong>, le propriétaire doit envoyer un avis écrit au moins <strong>3 mois avant la fin du bail</strong>. Le locataire a <strong>1 mois pour accepter ou refuser</strong>. En cas de refus, le propriétaire peut s'adresser au <strong>TAL</strong>.</div></div><div style='padding:6px 14px;background:#003087;color:#fff;font-size:0.8em;display:flex;justify-content:space-between;flex-wrap:wrap;gap:4px'><span>Signé le 12 juin 2025 à Montréal</span><span>Léa Tremblay ✍ &nbsp;&nbsp;&nbsp;&nbsp; Denis Beaumont ✍</span></div></div></div><h3>Tes droits comme locataire au Québec</h3><div style='background:#dcfce7;padding:10px;margin:10px 0;border-radius:4px'><strong>Si ton propriétaire ne fait pas les réparations :</strong> Tu peux faire une demande au TAL (Tribunal administratif du logement). Tu n'as PAS le droit de retenir ton loyer.<br><br><strong>Si tu reçois un avis d'expulsion :</strong> Lis l'avis attentivement. Dans la plupart des cas, tu as au moins <strong>3 mois</strong> pour partir, et tu peux contester au TAL.<br><br><strong>TAL (Tribunal administratif du logement) :</strong> 1 800 683-2245 · tal.gouv.qc.ca · Gratuit pour déposer une demande en ligne · Disponible en français</div>",
      order: 237,
    } as any);

