    // ── Cours 48 : Passer une entrevue d'emploi ───────────────────────────────
    const fpt48Id = randomUUID();
    this.courses.set(fpt48Id, {
      id: fpt48Id,
      title: "Passer une entrevue d'emploi",
      description: "Prépare-toi à une entrevue d'emploi en français : questions fréquentes, comment parler de toi, tenue vestimentaire, attitude à adopter et suivi post-entrevue",
      category: "francais_fpt",
      content: "<h2>Passer une entrevue d'emploi</h2><p>L'<strong>entrevue d'emploi</strong> (parfois appelée « entretien ») est une rencontre entre toi et l'employeur. Son but : vérifier si tu corresponds au poste et si tu t'intégreras bien à l'équipe. Une bonne préparation fait toute la différence. L'entrevue peut se dérouler <strong>en personne, par téléphone ou par vidéo (Teams, Zoom)</strong>.</p><div style='background:#fef9c3;border-left:4px solid #eab308;padding:12px;margin:15px 0;border-radius:4px'><strong>Avant l&apos;entrevue — Liste de vérification :</strong><br>✓ Relis l&apos;offre d&apos;emploi et note les compétences demandées<br>✓ Renseigne-toi sur l&apos;entreprise (son histoire, ses produits, ses valeurs)<br>✓ Prépare 3 à 5 exemples concrets de situations de travail (méthode STAR)<br>✓ Prépare tes questions pour l&apos;employeur (montre ton intérêt)<br>✓ Arrive 5 à 10 minutes en avance — jamais en retard<br>✓ Apporte une copie imprimée de ton CV</div><h3>Guide de préparation — Entrevue de Léa au Marché Beaumont</h3><div style='color-scheme:light;background:#e5e7eb;padding:14px;border-radius:8px;margin:10px 0'><div style='background:#ffffff;color:#111827;font-family:Arial,Helvetica,sans-serif;font-size:0.76em;max-width:700px;margin:0 auto;border:1px solid #9ca3af'><div style='background:#1e3a5f;color:#fff;padding:8px 14px'><strong>GUIDE DE PRÉPARATION À L&apos;ENTREVUE</strong><br><span style='font-size:0.85em;color:#93c5fd'>Léa Tremblay · Marché Beaumont · Poste : Caissière temps plein</span></div><div style='padding:10px 14px;border-bottom:1px solid #e5e7eb'><div style='font-weight:700;color:#1e3a5f;margin-bottom:8px;font-size:0.9em'>QUESTIONS FRÉQUENTES ET RÉPONSES MODÈLES</div><div style='margin-bottom:10px;border-left:3px solid #1e3a5f;padding-left:10px'><div style='font-weight:700;font-size:0.9em;color:#1e3a5f'>Q1 : « Parlez-moi de vous. »</div><div style='font-size:0.88em;color:#374151;margin-top:4px;line-height:1.6'><strong>Réponse de Léa :</strong> « Je m&apos;appelle Léa Tremblay. Je travaille actuellement comme caissière à l&apos;Épicerie Boni-Soir depuis bientôt deux ans et demi. Je suis en formation au CFP pour améliorer mon français et mes compétences professionnelles. J&apos;aime beaucoup le contact avec la clientèle et je suis reconnue pour mon efficacité et ma ponctualité. Je cherche maintenant un poste à temps plein dans une entreprise stable comme la vôtre. »</div></div><div style='margin-bottom:10px;border-left:3px solid #1e3a5f;padding-left:10px'><div style='font-weight:700;font-size:0.9em;color:#1e3a5f'>Q2 : « Pourquoi voulez-vous travailler chez nous ? »</div><div style='font-size:0.88em;color:#374151;margin-top:4px;line-height:1.6'><strong>Réponse de Léa :</strong> « J&apos;ai fait des recherches sur le Marché Beaumont et j&apos;ai vu que vous mettez l&apos;accent sur les produits locaux et le service personnalisé. C&apos;est une approche qui me correspond vraiment. Je cherche un environnement où je peux construire une relation de confiance avec les clients réguliers, ce qui est plus difficile dans les très grandes surfaces. »</div></div><div style='margin-bottom:10px;border-left:3px solid #1e3a5f;padding-left:10px'><div style='font-weight:700;font-size:0.9em;color:#1e3a5f'>Q3 : « Quelles sont vos forces et vos faiblesses ? »</div><div style='font-size:0.88em;color:#374151;margin-top:4px;line-height:1.6'><strong>Forces de Léa :</strong> « Je suis très fiable — je n&apos;ai aucun retard ni absence non justifiée depuis deux ans. Je suis également rapide à apprendre les nouveaux systèmes informatiques. »<br><strong>Faiblesse :</strong> « Parfois je veux trop bien faire et je passe plus de temps que nécessaire sur un dossier. J&apos;ai appris à mieux gérer mon temps en me fixant des priorités. »</div></div><div style='margin-bottom:10px;border-left:3px solid #1e3a5f;padding-left:10px'><div style='font-weight:700;font-size:0.9em;color:#1e3a5f'>Q4 : « Décrivez une situation difficile avec un client et comment vous l&apos;avez gérée. »</div><div style='font-size:0.88em;color:#374151;margin-top:4px;line-height:1.6'><strong>Méthode STAR :</strong><br><strong>Situation :</strong> Un client était mécontent car son coupon de réduction n&apos;avait pas été appliqué.<br><strong>Tâche :</strong> Gérer la situation sans créer de file d&apos;attente.<br><strong>Action :</strong> J&apos;ai calmement expliqué le problème, appelé ma superviseure et offert un bon de réduction pour sa prochaine visite.<br><strong>Résultat :</strong> Le client est reparti satisfait et a remercié la direction par courriel.</div></div><div style='border-left:3px solid #1e3a5f;padding-left:10px'><div style='font-weight:700;font-size:0.9em;color:#1e3a5f'>Q5 : « Avez-vous des questions pour nous ? »</div><div style='font-size:0.88em;color:#374151;margin-top:4px;line-height:1.6'><strong>Bonnes questions de Léa :</strong><br>« Quels sont les horaires typiques pour ce poste ? »<br>« Y a-t-il des possibilités de formation ou d&apos;avancement au sein du Marché Beaumont ? »<br>« Quelles sont les prochaines étapes du processus de sélection ? »</div></div></div><div style='padding:10px 14px;border-bottom:1px solid #e5e7eb;background:#f0f9ff'><div style='font-weight:700;color:#1e3a5f;margin-bottom:6px;font-size:0.9em'>TENUE VESTIMENTAIRE RECOMMANDÉE</div><table style='width:100%;border-collapse:collapse;font-size:0.88em'><tr style='background:#f9fafb'><th style='padding:4px 8px;border-bottom:1px solid #e5e7eb;text-align:left'>Type de poste</th><th style='padding:4px 8px;border-bottom:1px solid #e5e7eb;text-align:left'>Tenue suggérée</th></tr><tr><td style='padding:4px 8px'>Commerce de détail, caisse</td><td style='padding:4px 8px'>Pantalon propre (pas de jeans déchirés) + chemise ou blouse + chaussures fermées</td></tr><tr style='background:#f9fafb'><td style='padding:4px 8px'>Restauration, cuisine</td><td style='padding:4px 8px'>Vêtements propres, sobres, cheveux attachés, pas de parfum fort</td></tr><tr><td style='padding:4px 8px'>Bureau, administration</td><td style='padding:4px 8px'>Tenue professionnelle : pantalon/jupe + veste + souliers fermés</td></tr></table></div><div style='padding:10px 14px;background:#f0fdf4'><div style='font-weight:700;color:#1e3a5f;margin-bottom:6px;font-size:0.9em'>APRÈS L&apos;ENTREVUE — COURRIEL DE REMERCIEMENT</div><div style='font-size:0.88em;line-height:1.6'>Dans les <strong>24 heures</strong> suivant l&apos;entrevue, envoie un court courriel de remerciement :<br><br><em>« Madame Beaumont,<br>Je vous remercie chaleureusement pour le temps que vous m&apos;avez accordé lors de notre entrevue de ce matin. Notre échange a renforcé mon intérêt pour le poste de caissière au Marché Beaumont. Je reste disponible pour tout renseignement complémentaire.<br>Cordialement,<br>Léa Tremblay »</em><br><br>Ce geste simple te démarque de la plupart des autres candidats.</div></div><div style='padding:6px 14px;background:#1e3a5f;color:#fff;font-size:0.8em'>Conseil : Pratique tes réponses à voix haute avant l&apos;entrevue — l&apos;aisance s&apos;acquiert avec la répétition.</div></div></div>",
      order: 247,
    } as any);

    const fpt48ex1Id = randomUUID();
